module RefModule(input [15:0] vec, output reg [4:0] count);integer obf_i;
    integer result;
    always @(vec) begin
        result = 0;
        for (obf_i=15; obf_i>=0; obf_i=obf_i-1) begin
            if(vec[obf_i] == 1'b1) begin
                result = result + 1;
            end
        end
        count = result;
    end
endmodule
